<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class ScheduleChangeController{public function publicForm(string $token):void{$pdo=Database::connection();$q=$pdo->prepare('SELECT j.*,c.display_name FROM jobs j JOIN customers c ON c.id=j.customer_id WHERE SHA2(CONCAT(j.id,j.job_number),256)=?');$q->execute([$token]);$job=$q->fetch();if(!$job){http_response_code(404);exit('Job not found.');}View::render('customer/change-schedule',['title'=>'Change Appointment','job'=>$job,'token'=>$token],'public');}public function submit(string $token):void{verify_csrf();$pdo=Database::connection();$q=$pdo->prepare('SELECT id,customer_id FROM jobs WHERE SHA2(CONCAT(id,job_number),256)=?');$q->execute([$token]);$job=$q->fetch();if(!$job){http_response_code(404);exit('Job not found.');}$pdo->prepare('INSERT INTO customer_schedule_changes(job_id,customer_id,public_token,request_type,requested_start,reason) VALUES(?,?,?,?,?,?)')->execute([$job['id'],$job['customer_id'],public_token(),$_POST['request_type'],($_POST['requested_start']??'')?:null,trim($_POST['reason']??'')]);View::render('customer/schedule-success',['title'=>'Request Received'],'public');}public function index():void{Auth::requireRole('owner','office');$rows=Database::connection()->query('SELECT s.*,j.job_number,c.display_name FROM customer_schedule_changes s JOIN jobs j ON j.id=s.job_id JOIN customers c ON c.id=s.customer_id ORDER BY s.created_at DESC')->fetchAll();View::render('portal/schedule-changes/index',['title'=>'Schedule Changes','rows'=>$rows],'portal');}public function decide(string $id):void{Auth::requireRole('owner','office');verify_csrf();$pdo=Database::connection();$status=$_POST['status'];$pdo->prepare('UPDATE customer_schedule_changes SET status=?,reviewed_by=?,reviewed_at=NOW() WHERE id=?')->execute([$status,Auth::id(),(int)$id]);if($status==='approved'){$q=$pdo->prepare('SELECT * FROM customer_schedule_changes WHERE id=?');$q->execute([(int)$id]);$r=$q->fetch();if($r['request_type']==='cancel')$pdo->prepare("UPDATE jobs SET status='cancelled' WHERE id=?")->execute([$r['job_id']]);elseif($r['requested_start'])$pdo->prepare("UPDATE jobs SET scheduled_start=?,status='scheduled' WHERE id=?")->execute([$r['requested_start'],$r['job_id']]);}AuditService::log('schedule_change.decided','customer_schedule_change',(int)$id,['status'=>$status]);flash('success','Schedule request updated.');redirect('/portal/schedule-changes');}}
